 10→{
 11→	Super::NativeOnInitialized();
 12→
 13→	if (Button_Purchase) Button_Purchase->OnClicked.AddDynamic(this, &ULFPShopWidget::OnPurchaseClicked);
 14→	if (Button_Close) Button_Close->OnClicked.AddDynamic(this, &ULFPShopWidget::OnCloseClicked);
