 17→void ULFPShopWidget::Setup(ULFPGameInstance* GI, FName InShopID, const FLFPShopDefinition& InShopDefinition)
 18→{
 19→	CachedGameInstance = GI;
 20→	CachedShopID = InShopID;
 21→	CachedShopDefinition = InShopDefinition;
 22→	SelectedRelicIndex = CachedShopDefinition.RelicList.Num() > 0 ? 0 : INDEX_NONE;
 23→	RefreshShopUI();
