 26→void ULFPShopWidget::RefreshShopUI()
 27→{
 28→	if (Text_Title)
 29→	{
 30→		Text_Title->SetText(CachedShopDefinition.DisplayName.IsEmpty() ? FText::FromString(TEXT("遗物商店")) : CachedShopDefinition.DisplayName);
 31→	}
 32→
 33→	if (Text_Gold && CachedGameInstance)
 34→	{
 35→		Text_Gold->SetText(FText::FromString(FString::Printf(TEXT("金币: %d"), CachedGameInstance->GetGold())));
 36→	}
 37→
 38→	RefreshRelicList();
 39→	RefreshDetailPanel();
 40→}
 41→
 42→void ULFPShopWidget::RefreshRelicList()
 43→{
 44→	RelicButtons.Empty();
 45→	ButtonToRelicIndexMap.Empty();
 46→
 47→	if (Box_RelicList)
 48→	{
 49→		Box_RelicList->ClearChildren();
 50→	}
 51→
 52→	if (!CachedGameInstance || !Box_RelicList)
 53→	{
 54→		return;
 55→	}
 56→
 57→	for (int32 i = 0; i < CachedShopDefinition.RelicList.Num(); ++i)
 58→	{
 59→		const FLFPShopRelicEntry& Entry = CachedShopDefinition.RelicList[i];
 60→		FLFPRelicDefinition RelicDefinition;
 61→		if (!CachedGameInstance->FindRelicDefinition(Entry.RelicID, RelicDefinition))
 62→		{
 63→			continue;
 64→		}
 65→
 66→		UButton* RelicButton = NewObject<UButton>(this);
 67→		if (!RelicButton)
 68→		{
 69→			continue;
 70→		}
 71→
 72→		UTextBlock* Label = NewObject<UTextBlock>(RelicButton);
 73→		if (Label)
 74→		{
 75→			FString Suffix;
 76→			if (CachedGameInstance->HasRelic(Entry.RelicID))
 77→			{
 78→				Suffix = TEXT(" [已拥有]");
 79→			}
 80→			else if (!CachedGameInstance->CanAffordGold(Entry.Price))
 81→			{
 82→				Suffix = TEXT(" [金币不足]");
 83→			}
 84→
 85→			Label->SetText(FText::FromString(FString::Printf(TEXT("%s - %d%s"), *RelicDefinition.DisplayName.ToString(), Entry.Price, *Suffix)));
 86→			RelicButton->AddChild(Label);
 87→		}
 88→
 89→		UVerticalBoxSlot* ItemSlot = Box_RelicList->AddChildToVerticalBox(RelicButton);
 90→		if (ItemSlot)
 91→		{
 92→			ItemSlot->SetPadding(FMargin(4.f));
 93→		}
 94→
 95→		RelicButton->OnClicked.AddDynamic(this, &ULFPShopWidget::OnRelicButtonClicked);
 96→		RelicButtons.Add(RelicButton);
 97→		ButtonToRelicIndexMap.Add(RelicButton, i);
 98→	}
 99→}
