101→void ULFPShopWidget::RefreshDetailPanel()
102→{
103→	if (!CachedGameInstance)
104→	{
105→		return;
106→	}
107→
108→	if (!CachedShopDefinition.RelicList.IsValidIndex(SelectedRelicIndex))
109→	{
110→		if (Text_SelectedName) Text_SelectedName->SetText(FText::FromString(TEXT("未选择遗物")));
111→		if (Text_SelectedDescription) Text_SelectedDescription->SetText(FText::GetEmpty());
112→		if (Text_SelectedPrice) Text_SelectedPrice->SetText(FText::GetEmpty());
113→		if (Text_Status) Text_Status->SetText(FText::GetEmpty());
114→		if (Button_Purchase) Button_Purchase->SetIsEnabled(false);
115→		if (Image_SelectedRelic) Image_SelectedRelic->SetBrushFromTexture(nullptr);
116→		return;
117→	}
118→
119→	const FLFPShopRelicEntry& Entry = CachedShopDefinition.RelicList[SelectedRelicIndex];
120→	FLFPRelicDefinition Definition;
121→	if (!CachedGameInstance->FindRelicDefinition(Entry.RelicID, Definition))
122→	{
123→		if (Text_Status) Text_Status->SetText(FText::FromString(TEXT("遗物定义缺失")));
124→		if (Button_Purchase) Button_Purchase->SetIsEnabled(false);
125→		return;
126→	}
127→
128→	if (Image_SelectedRelic)
129→	{
130→		Image_SelectedRelic->SetBrushFromTexture(Definition.Icon);
131→	}
132→	if (Text_SelectedName)
133→	{
134→		Text_SelectedName->SetText(Definition.DisplayName);
135→	}
136→	if (Text_SelectedDescription)
137→	{
138→		Text_SelectedDescription->SetText(FText::FromString(FString::Printf(TEXT("%s\n%s"), *Definition.Description.ToString(), *BuildEffectDescription(Definition))));
139→	}
140→	if (Text_SelectedPrice)
141→	{
142→		Text_SelectedPrice->SetText(FText::FromString(FString::Printf(TEXT("价格: %d"), Entry.Price)));
143→	}
144→
145→	bool bOwned = CachedGameInstance->HasRelic(Entry.RelicID);
146→	bool bCanAfford = CachedGameInstance->CanAffordGold(Entry.Price);
147→	if (Button_Purchase)
148→	{
149→		Button_Purchase->SetIsEnabled(!bOwned && bCanAfford);
150→	}
151→	if (Text_Status)
152→	{
153→		if (bOwned)
154→		{
155→			Text_Status->SetText(FText::FromString(TEXT("已拥有")));
156→		}
157→		else if (!bCanAfford)
158→		{
159→			Text_Status->SetText(FText::FromString(TEXT("金币不足")));
160→		}
161→		else
162→		{
163→			Text_Status->SetText(FText::FromString(TEXT("可购买")));
164→		}
165→	}
166→}
