168→FString ULFPShopWidget::BuildEffectDescription(const FLFPRelicDefinition& Definition) const
169→{
170→	TArray<FString> Parts;
171→	for (const FLFPRelicEffectEntry& Effect : Definition.Effects)
172→	{
173→		switch (Effect.EffectType)
174→		{
175→		case ELFPRelicEffectType::RET_MaxHealthFlat:
176→			Parts.Add(FString::Printf(TEXT("最大生命 %+d"), Effect.Value));
177→			break;
178→		case ELFPRelicEffectType::RET_AttackFlat:
179→			Parts.Add(FString::Printf(TEXT("攻击力 %+d"), Effect.Value));
180→			break;
181→		case ELFPRelicEffectType::RET_DefenseFlat:
182→			Parts.Add(FString::Printf(TEXT("防御力 %+d"), Effect.Value));
183→			break;
184→		case ELFPRelicEffectType::RET_SpeedFlat:
185→			Parts.Add(FString::Printf(TEXT("速度 %+d"), Effect.Value));
186→			break;
187→		default:
188→			break;
189→		}
190→	}
191→
192→	return Parts.Num() > 0 ? FString::Join(Parts, TEXT("\n")) : TEXT("无效果");
193→}
194→
195→void ULFPShopWidget::OnRelicButtonClicked()
196→{
197→	for (const auto& Pair : ButtonToRelicIndexMap)
198→	{
199→		if (Pair.Key && Pair.Key->IsHovered())
200→		{
201→			SelectedRelicIndex = Pair.Value;
202→			RefreshDetailPanel();
203→			return;
204→		}
205→	}
206→}
207→
208→void ULFPShopWidget::OnPurchaseClicked()
209→{
210→	if (!CachedGameInstance || !CachedShopDefinition.RelicList.IsValidIndex(SelectedRelicIndex))
211→	{
212→		return;
213→	}
214→
215→	const FLFPShopRelicEntry& Entry = CachedShopDefinition.RelicList[SelectedRelicIndex];
216→	if (CachedGameInstance->TryPurchaseRelic(Entry.RelicID, Entry.Price))
217→	{
218→		RefreshShopUI();
219→	}
220→}
221→
222→void ULFPShopWidget::OnCloseClicked()
223→{
224→	SetVisibility(ESlateVisibility::Collapsed);
225→	RemoveFromParent();
226→	OnClosed.Broadcast();
227→}
