 47→void ULFPGameInstance::TransitionToBattle(const FString& BattleLevelName)
 48→{
 49→	if (bIsTransitioning) return;
 50→	bIsTransitioning = true;
 51→
 52→	FString LevelName = BattleLevelName.IsEmpty() ? DefaultBattleLevelName : BattleLevelName;
 53→	UE_LOG(LogTemp, Log, TEXT("切换到战斗关卡: %s"), *LevelName);
 54→
 55→	// 淡出到黑
 56→	UWorld* World = GetWorld();
 57→	if (World)
 58→	{
 59→		APlayerController* PC = World->GetFirstPlayerController();
 60→		if (PC && PC->PlayerCameraManager)
 61→		{
 62→			PC->PlayerCameraManager->StartCameraFade(0.f, 1.f, TransitionFadeDuration, FLinearColor::Black, false, true);
 63→		}
 64→
 65→		// 延迟后加载关卡
 66→		FTimerHandle TimerHandle;
 67→		FString CapturedLevelName = LevelName;
 68→		World->GetTimerManager().SetTimer(TimerHandle, [this, CapturedLevelName]()
 69→		{
 70→			bIsTransitioning = false;
 71→			UGameplayStatics::OpenLevel(this, FName(*CapturedLevelName));
 72→		}, TransitionFadeDuration, false);
 73→	}
 74→	else
 75→	{
 76→		bIsTransitioning = false;
 77→		UGameplayStatics::OpenLevel(this, FName(*LevelName));
 78→	}
 79→}
