129→bool ULFPGameInstance::SpendGold(int32 Amount)
130→{
131→	if (Amount < 0)
132→	{
133→		return false;
134→	}
135→
136→	if (!CanAffordGold(Amount))
137→	{
138→		UE_LOG(LogTemp, Warning, TEXT("金币不足: 需要 %d, 当前 %d"), Amount, Gold);
139→		return false;
140→	}
141→
142→	Gold -= Amount;
143→	UE_LOG(LogTemp, Log, TEXT("金币变动: -%d, 当前: %d"), Amount, Gold);
144→	return true;
145→}
