162→bool ULFPGameInstance::TryPurchaseRelic(FName RelicID, int32 Price)
163→{
164→	if (RelicID == NAME_None)
165→	{
166→		UE_LOG(LogTemp, Warning, TEXT("TryPurchaseRelic: RelicID 无效"));
167→		return false;
168→	}
169→
170→	FLFPRelicDefinition RelicDefinition;
171→	if (!FindRelicDefinition(RelicID, RelicDefinition))
172→	{
173→		UE_LOG(LogTemp, Warning, TEXT("TryPurchaseRelic: 未找到遗物 %s"), *RelicID.ToString());
174→		return false;
175→	}
176→
177→	if (HasRelic(RelicID))
178→	{
179→		UE_LOG(LogTemp, Warning, TEXT("TryPurchaseRelic: 已拥有遗物 %s"), *RelicID.ToString());
180→		return false;
181→	}
182→
183→	if (!SpendGold(Price))
184→	{
185→		return false;
186→	}
187→
188→	OwnedRelicIDs.Add(RelicID);
189→	UE_LOG(LogTemp, Log, TEXT("购买遗物成功: %s"), *RelicID.ToString());
190→	return true;
191→}
