193→void ULFPGameInstance::ApplyOwnedRelicsToUnit(ALFPTacticsUnit* Unit) const
194→{
195→	if (!Unit || !RelicDataAsset)
196→	{
197→		return;
198→	}
199→
200→	for (const FName& RelicID : OwnedRelicIDs)
201→	{
202→		FLFPRelicDefinition Definition;
203→		if (!FindRelicDefinition(RelicID, Definition))
204→		{
205→			continue;
206→		}
207→
208→		for (const FLFPRelicEffectEntry& Effect : Definition.Effects)
209→		{
210→			switch (Effect.EffectType)
211→			{
212→			case ELFPRelicEffectType::RET_MaxHealthFlat:
213→				Unit->AddCurrentMaxHealth(Effect.Value);
214→				break;
215→			case ELFPRelicEffectType::RET_AttackFlat:
216→				Unit->AddCurrentAttack(Effect.Value);
217→				break;
218→			case ELFPRelicEffectType::RET_DefenseFlat:
219→				Unit->AddCurrentPhysicalBlock(Effect.Value);
220→				break;
221→			case ELFPRelicEffectType::RET_SpeedFlat:
222→				Unit->AddCurrentSpeed(Effect.Value);
223→				break;
224→			default:
225→				break;
226→			}
227→		}
228→	}
229→}
