232→
233→bool ULFPGameInstance::TryAddUnit(const FLFPUnitEntry& Unit)
234→{
235→	if (!Unit.IsValid()) return false;
236→
237→	if (!IsPartyFull())
238→	{
239→		PartyUnits.Add(Unit);
240→		UE_LOG(LogTemp, Log, TEXT("单位 %s 加入出战队伍（%d/%d）"), *Unit.TypeID.ToString(), PartyUnits.Num(), MaxPartySize);
241→		return true;
242→	}
243→	if (!IsReserveFull())
244→	{
245→		ReserveUnits.Add(Unit);
246→		UE_LOG(LogTemp, Log, TEXT("单位 %s 加入备战营（%d/%d）"), *Unit.TypeID.ToString(), ReserveUnits.Num(), MaxReserveSize);
247→		return true;
248→	}
249→	return false;
250→}
