261→void ULFPGameInstance::ReplaceReserveUnit(int32 SlotIndex, const FLFPUnitEntry& NewUnit)
262→{
263→	if (ReserveUnits.IsValidIndex(SlotIndex))
264→	{
265→		UE_LOG(LogTemp, Log, TEXT("替换备战营槽 %d: %s → %s"), SlotIndex, *ReserveUnits[SlotIndex].TypeID.ToString(), *NewUnit.TypeID.ToString());
266→		ReserveUnits[SlotIndex] = NewUnit;
267→	}
268→}
269→
270→void ULFPGameInstance::RemovePartyUnit(int32 SlotIndex)
271→{
272→	if (PartyUnits.IsValidIndex(SlotIndex))
273→	{
274→		UE_LOG(LogTemp, Log, TEXT("移除队伍槽 %d: %s"), SlotIndex, *PartyUnits[SlotIndex].TypeID.ToString());
275→		PartyUnits.RemoveAt(SlotIndex);
276→	}
277→}
278→
279→void ULFPGameInstance::RemoveReserveUnit(int32 SlotIndex)
280→{
