120→void ALFPTurnGameMode::OnBattleResultConfirmed()
121→{
122→    ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
123→    if (!GI) return;
124→
125→    // 写回战斗结果
126→    GI->SetBattleResult(CachedBattleResult);
127→
128→    // 移除结算 UI
129→    if (BattleResultWidget)
130→    {
131→        BattleResultWidget->OnConfirmPressed.RemoveDynamic(this, &ALFPTurnGameMode::OnBattleResultConfirmed);
132→        BattleResultWidget->RemoveFromParent();
133→        BattleResultWidget = nullptr;
134→    }
135→
136→    // 恢复输入模式
137→    if (APlayerController* PC = GetWorld()->GetFirstPlayerController())
138→    {
139→        FInputModeGameAndUI InputMode;
140→        PC->SetInputMode(InputMode);
141→    }
142→
143→    // 返回世界地图
144→    if (CachedBattleRequest.bIsValid)
145→    {
