128→void ALFPWorldMapGameMode::ProcessCapturedUnits(const TArray<FLFPUnitEntry>& CapturedUnits)
129→{
130→	ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
131→	if (!GI) return;
132→
133→	for (const FLFPUnitEntry& Unit : CapturedUnits)
134→	{
135→		if (!GI->TryAddUnit(Unit))
136→		{
137→			// 队伍和备战营都满了，加入待处理队列
138→			PendingCapturedUnits.Add(Unit);
139→		}
140→	}
141→
142→	// 有待处理的，显示替换 UI
143→	if (PendingCapturedUnits.Num() > 0)
144→	{
145→		ShowNextReplacementUI();
146→	}
147→}
